        waveProperties: {
            category: 'domain',
            lesson:   'waves',
            description: 'Wave equation v = fλ with variable definitions and derived form v = λ/T; energy-amplitude relationship E ∝ A²; worked example calculating radio wave wavelength at 99.0 MHz; note on fixed speed within a medium and inverse proportionality of f and λ'
        },
        transverseAndLongitudinal: {
            category: 'domain',
            lesson:   'waves',
            description: 'Transverse waves: perpendicular oscillation, examples (EM waves, water surface, rope, seismic S-waves), vacuum travel, polarisation capability; longitudinal waves: parallel oscillation, compressions and rarefactions, examples (sound, seismic P-waves, ultrasound, slinky), medium requirement, no polarisation; worked example comparing sound wavelength in air (340 m/s) vs water (1480 m/s) at 440 Hz with frequency invariance explanation'
        },
        waveBehaviour: {
            category: 'domain',
            lesson:   'waves',
            description: 'Reflection (law θi = θr, fixed-end inversion vs free-end non-inversion, applications); refraction (Snell\'s Law n1 sinθ1 = n2 sinθ2, worked example light air-to-glass at 35°, bending-toward/away-from normal rules); diffraction (maximum when gap ≈ λ, applications from radio waves to X-ray crystallography); superposition (principle, constructive interference path difference = nλ, destructive = (n+½)λ, worked example with two loudspeakers at 680 Hz); standing waves (formation, nodes/antinodes spacing λ/2 and λ/4, harmonic series for string fₙ = nv/2L, open pipe same, closed pipe odd harmonics only fₙ = nv/4L, string resonance worked example)'
        },
        soundWaves: {
            category: 'domain',
            lesson:   'waves',
            description: 'Nature of sound as longitudinal mechanical wave; speed in media (air 340 m/s, water 1480 m/s, steel 5100 m/s, vacuum 0) and temperature dependence v ≈ 331 + 0.6T; intensity I = P/A and inverse square law I ∝ 1/r²; decibel scale L = 10 log10(I/I0) with I0 = 10⁻¹² W/m²; worked example: point source at 3.0 m and 9.0 m calculating intensity drop and dB levels'
        },
        electromagneticSpectrum: {
            category: 'domain',
            lesson:   'waves',
            description: 'Common properties of all EM waves (transverse, c = 3×10⁸ m/s in vacuum, no medium required, mutually perpendicular E and B fields); all seven regions tabulated with wavelength range, frequency range, and named applications; ionising vs non-ionising boundary at UV — radio/microwave/infrared non-ionising; UV/X-ray/gamma ionising with molecular damage mechanism'
        },
        factorsAffectingWaves: {
            category: 'domain',
            lesson:   'waves',
            description: 'Medium properties: density (greater density generally reduces speed), elasticity (greater stiffness increases speed, v ∝ √(E/ρ)), temperature (raises gas molecular speed, raises sound speed); wave source: frequency fixed by source and unchanged by medium, amplitude set by source energy and reduced by inverse square law and absorption; geometry: gap width determines diffraction degree, distance from source governs intensity via I ∝ 1/r²'
        },

